// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === '') {
		return;
	} else {
		_changeMember();
	}

	function _changeMember(){
		// STRY0050440 
		var member_user = g_form.getValue('office_member');
		var member_user_display = g_form.getDisplayValue('office_member');
		if(g_form.getControl("u_organizational_user")){
			g_form.setValue("u_organizational_user", member_user, member_user_display);
		}
	}
}
